import android.content.Context
import android.content.Intent
import android.net.Uri
import android.os.Build
import android.provider.MediaStore
import android.webkit.JavascriptInterface
import android.webkit.WebView
import android.webkit.WebViewClient
import androidx.appcompat.app.AppCompatActivity
import androidx.core.content.ContextCompat
import android.Manifest
import android.content.pm.PackageManager
import android.webkit.ValueCallback
import android.widget.Toast
import androidx.core.app.ActivityCompat
import androidx.core.content.ContextCompat.checkSelfPermission
import android.app.Activity
import android.app.NotificationChannel
import android.app.NotificationManager
import android.os.Build.VERSION_CODES
import androidx.core.app.NotificationCompat
import android.app.NotificationManager.IMPORTANCE_DEFAULT

class HybridWebViewBridge(
    private val activity: AppCompatActivity,
    private val webView: WebView
) {
    private var fileChooserCallback: ValueCallback<Array<Uri>>? = null
    private val REQUEST_CAMERA_PERMISSION = 1001
    private val REQUEST_CAMERA = 1002
    private val REQUEST_NOTIFICATION_PERMISSION = 1003

    init {
        webView.apply {
            settings.apply {
                javaScriptEnabled = true
                domStorageEnabled = true
                allowFileAccess = true
                allowContentAccess = true
                allowFileAccessFromFileURLs = true
                allowUniversalAccessFromFileURLs = true
            }
            webViewClient = object : WebViewClient() {
                override fun shouldOverrideUrlLoading(view: WebView?, url: String?): Boolean {
                    view?.loadUrl(url)
                    return true
                }
            }
            addJavascriptInterface(this@HybridWebViewBridge, "AndroidBridge")
        }
    }

    @JavascriptInterface
    fun openCamera() {
        activity.runOnUiThread {
            if (checkSelfPermission(activity, Manifest.permission.CAMERA) != PackageManager.PERMISSION_GRANTED) {
                ActivityCompat.requestPermissions(activity, arrayOf(Manifest.permission.CAMERA), REQUEST_CAMERA_PERMISSION)
            } else {
                openCameraIntent()
            }
        }
    }

    @JavascriptInterface
    fun saveToLocalStorage(key: String, value: String) {
        val prefs = activity.getSharedPreferences("webapp_storage", Context.MODE_PRIVATE)
        prefs.edit().putString(key, value).apply()
    }

    @JavascriptInterface
    fun getFromLocalStorage(key: String): String {
        val prefs = activity.getSharedPreferences("webapp_storage", Context.MODE_PRIVATE)
        return prefs.getString(key, "") ?: ""
    }

    @JavascriptInterface
    fun showNotification(title: String, message: String) {
        activity.runOnUiThread {
            if (checkSelfPermission(activity, Manifest.permission.POST_NOTIFICATIONS) != PackageManager.PERMISSION_GRANTED) {
                ActivityCompat.requestPermissions(activity, arrayOf(Manifest.permission.POST_NOTIFICATIONS), REQUEST_NOTIFICATION_PERMISSION)
            } else {
                showNotificationInternal(title, message)
            }
        }
    }

    @JavascriptInterface
    fun shareContent(text: String) {
        activity.runOnUiThread {
            val sendIntent = Intent().apply {
                action = Intent.ACTION_SEND
                putExtra(Intent.EXTRA_TEXT, text)
                type = "text/plain"
            }
            val shareIntent = Intent.createChooser(sendIntent, null)
            activity.startActivity(shareIntent)
        }
    }

    @JavascriptInterface
    fun openFilePicker() {
        activity.runOnUiThread {
            val intent = Intent(Intent.ACTION_GET_CONTENT).apply {
                type = "*/*"
            }
            try {
                activity.startActivityForResult(intent, 1004)
            } catch (e: Exception) {
                Toast.makeText(activity, "No file picker available", Toast.LENGTH_SHORT).show()
            }
        }
    }

    private fun openCameraIntent() {
        val intent = Intent(MediaStore.ACTION_IMAGE_CAPTURE)
        if (intent.resolveActivity(activity.packageManager) != null) {
            activity.startActivityForResult(intent, REQUEST_CAMERA)
        }
    }

    private fun showNotificationInternal(title: String, message: String) {
        val channelId = "webapp_notifications"
        val notificationManager = ContextCompat.getSystemService(activity, NotificationManager::class.java)
        
        if (Build.VERSION.SDK_INT >= VERSION_CODES.O) {
            val channel = NotificationChannel(channelId, "Web App Notifications", IMPORTANCE_DEFAULT)
            notificationManager?.createNotificationChannel(channel)
        }

        val notification = NotificationCompat.Builder(activity, channelId)
            .setContentTitle(title)
            .setContentText(message)
            .setSmallIcon(android.R.drawable.ic_dialog_info)
            .setAutoCancel(true)
            .build()

        notificationManager?.notify(0, notification)
    }

    fun onActivityResult(requestCode: Int, resultCode: Int, data: Intent?) {
        when (requestCode) {
            REQUEST_CAMERA -> {
                if (resultCode == Activity.RESULT_OK) {
                    webView.loadUrl("javascript:cameraSuccess()")
                }
            }
            1004 -> {
                if (resultCode == Activity.RESULT_OK) {
                    val uri = data?.data
                    uri?.let {
                        webView.loadUrl("javascript:fileSelected('${it.toString()}')")
                    }
                }
            }
        }
    }

    fun onRequestPermissionsResult(requestCode: Int, permissions: Array<out String>, grantResults: IntArray) {
        when (requestCode) {
            REQUEST_CAMERA_PERMISSION -> {
                if (grantResults.isNotEmpty() && grantResults[0] == PackageManager.PERMISSION_GRANTED) {
                    openCameraIntent()
                }
            }
            REQUEST_NOTIFICATION_PERMISSION -> {
                if (grantResults.isNotEmpty() && grantResults[0] == PackageManager.PERMISSION_GRANTED) {
                    // Permission granted, notifications can be shown
                }
            }
        }
    }
}